program Main(input, output);
var a, b : integer;
procedure P(x, y, z : integer);
begin
  y := y + 1;
  z := x + x
end;
begin
  a := 2;
  b := 3;
  P(a, b, b);
  writeln(a, b)
end.

A. a = 2, b = 3
B. a = 2, b = 4
C. a = 2, b = 7
D. a = 4, b = 4

